mapper.select:
SELECT -- Vé v.maVe, v.gheNgoi, v.maHanhKhach, v.maChuyen, v.ngayMua, v.maXe as ve_maXe, CONCAT_WS('-', v.maTuyen, v.maXe, v.maChuyen, v.maVe) AS maVeFull,
-- Hành khách p.maHanhKhach AS p_maHanhKhach, p.hoTen AS p_hoTen, p.soDienThoai AS p_soDienThoai, p.cmnd AS p_cmnd,
-- Chuyến xe cx.maChuyen AS t_maChuyen, cx.ngayGioKhoiHanh AS t_ngayGioKhoiHanh, cx.ngayGioDen AS t_ngayGioDen, td.diemKhoiHanh AS t_diemDi, td.diemDen AS t_diemDen, cx.tinhTrangChuyen AS t_tinhTrangChuyen,
-- Giá vé gv.maGiaVe, gv.maTuyen, gv.maMua, gv.giaVe AS gv_giaVe, gv.ngayBatDau AS gv_ngayBatDau, gv.ngayKetThuc AS gv_ngayKetThuc,
-- Xe x.maXe as xe_maXe, x.bienSo,
-- Tuyến đường td.maTuyen, td.diemDen, td.diemKhoiHanh, td.khoangCach,
-- Lương tuyến đường ltd.maLuongTuyen AS ltd_maLuongTuyen, ltd.luongCoBan AS ltd_luongCoBan
FROM Ve v LEFT JOIN HanhKhach p ON v.maHanhKhach = p.maHanhKhach LEFT JOIN ChuyenXe cx ON v.maChuyen = cx.maChuyen AND v.maXe = cx.maXe AND v.maTuyen = cx.maTuyen LEFT JOIN Xe x ON cx.maXe = x.maXe LEFT JOIN GiaVe gv ON cx.maTuyen = gv.maTuyen AND cx.maMua = gv.maMua AND cx.maGiaVe = gv.maGiaVe LEFT JOIN TuyenDuong td ON cx.maTuyen = td.maTuyen LEFT JOIN LuongTuyenDuong ltd ON td.maLuongTuyen = ltd.maLuongTuyen WHERE 1=1
AND (p.hoTen LIKE CONCAT('%', #{keyword}, '%') OR p.soDienThoai LIKE CONCAT('%', #{keyword}, '%'))
AND CONCAT(v.maTuyen, '-', v.maXe, '-', v.maChuyen, '-', v.maVe) LIKE CONCAT('%', #{maVeFull}, '%')
AND DATE(v.ngayMua) >= #{muaTuNgay}
AND DATE(v.ngayMua) <= #{muaDenNgay}
AND DATE(cx.ngayGioKhoiHanh) >= #{khoiHanhTuNgay}
AND DATE(cx.ngayGioKhoiHanh) <= #{khoiHanhDenNgay}
AND td.diemKhoiHanh LIKE CONCAT('%', #{diemKhoiHanh}, '%')
AND td.diemDen LIKE CONCAT('%', #{diemDen}, '%')
AND cx.tinhTrangChuyen = #{tinhTrangChuyen}
ORDER BY v.ngayMua DESC
LIMIT #{limit} OFFSET #{offset}

SELECT count(*) FROM Ve v LEFT JOIN HanhKhach p ON v.maHanhKhach = p.maHanhKhach LEFT JOIN ChuyenXe cx ON v.maChuyen = cx.maChuyen AND v.maXe = cx.maXe AND v.maTuyen = cx.maTuyen LEFT JOIN Xe x ON cx.maXe = x.maXe LEFT JOIN GiaVe gv ON cx.maTuyen = gv.maTuyen AND cx.maMua = gv.maMua AND cx.maGiaVe = gv.maGiaVe LEFT JOIN TuyenDuong td ON cx.maTuyen = td.maTuyen LEFT JOIN LuongTuyenDuong ltd ON td.maLuongTuyen = ltd.maLuongTuyen WHERE 1=1
AND (p.hoTen LIKE CONCAT('%', #{keyword}, '%') OR p.soDienThoai LIKE CONCAT('%', #{keyword}, '%'))
AND CONCAT(v.maTuyen, '-', v.maXe, '-', v.maChuyen, '-', v.maVe) LIKE CONCAT('%', #{maVeFull}, '%')
AND DATE(v.ngayMua) >= #{muaTuNgay}
AND DATE(v.ngayMua) <= #{muaDenNgay}
AND DATE(cx.ngayGioKhoiHanh) >= #{khoiHanhTuNgay}
AND DATE(cx.ngayGioKhoiHanh) <= #{khoiHanhDenNgay}
AND td.diemKhoiHanh LIKE CONCAT('%', #{diemKhoiHanh}, '%')
AND td.diemDen LIKE CONCAT('%', #{diemDen}, '%')
AND cx.tinhTrangChuyen = #{tinhTrangChuyen}

mapper.update:
	    UPDATE Ve
	    SET gheNgoi = #{gheNgoi},
	        ngayMua = now()
	    WHERE maVe = #{maVe}
	    AND maXe = #{maXe}
        AND maTuyen = #{maTuyen}
        AND maChuyen = #{maChuyen}

mapper.delete:
	    DELETE FROM Ve
	    WHERE maVe = #{maVe}
        AND maXe = #{maXe}
        AND maTuyen = #{maTuyen}
        AND maChuyen = #{maChuyen}
